mapper.select:
SELECT payment_id, appointment_id, payment_amount, payment_method,
       payment_status, transaction_id, payment_time, create_time, update_time
FROM payment

    AND appointment_id = #{appointmentId, jdbcType=BIGINT}
    AND payment_status = #{paymentStatus}
    AND payment_method = #{paymentMethod}

ORDER BY create_time DESC

mapper.update:
UPDATE payment
appointment_id = #{appointmentId, jdbcType=BIGINT}, payment_amount = #{paymentAmount}, payment_method = #{paymentMethod}, payment_status = #{paymentStatus}, transaction_id = #{transactionId}, payment_time = #{paymentTime},
WHERE payment_id = #{paymentId}

UPDATE payment
SET payment_status = #{paymentStatus},
    transaction_id = #{transactionId}
WHERE payment_id = #{paymentId}
